import{_ as o,o as n,c as i,ag as t}from"./chunks/framework.Culc7SYV.js";const g=JSON.parse('{"title":"Companion Setting Up","description":"","frontmatter":{},"headers":[],"relativePath":"Companion-Setting-Up.md","filePath":"Companion-Setting-Up.md","lastUpdated":null}'),a={name:"Companion-Setting-Up.md"};function r(s,e,l,d,p,c){return n(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="companion-setting-up" tabindex="-1">Companion Setting Up <a class="header-anchor" href="#companion-setting-up" aria-label="Permalink to &quot;Companion Setting Up&quot;">​</a></h1><p>Last modified: 10/03/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Use this page to set up Companion (LearnKit&#39;s AI companion) safely before first use.</p><h2 id="_1-enable-companion" tabindex="-1">1. Enable Companion <a class="header-anchor" href="#_1-enable-companion" aria-label="Permalink to &quot;1. Enable Companion&quot;">​</a></h2><p>Open <strong>Settings -&gt; Companion</strong> and turn on <strong>Enable Companion</strong>.</p><p>Companion will not run until it is enabled and an API key is configured.</p><h2 id="_2-choose-provider-and-model" tabindex="-1">2. Choose provider and model <a class="header-anchor" href="#_2-choose-provider-and-model" aria-label="Permalink to &quot;2. Choose provider and model&quot;">​</a></h2><p>In <strong>Settings -&gt; Companion -&gt; AI Provider</strong>:</p><ul><li>Choose a provider: <strong>Anthropic</strong>, <strong>DeepSeek</strong>, <strong>Google</strong>, <strong>OpenAI</strong>, <strong>OpenRouter</strong>, <strong>Perplexity</strong>, <strong>xAI</strong>, or <strong>Custom</strong>.</li><li>Choose a model for that provider.</li><li>If using <strong>OpenRouter</strong>, set <strong>OpenRouter model access</strong> to <strong>Free</strong> or <strong>Paid</strong>.</li><li>If using <strong>Custom</strong>, set <strong>Endpoint override</strong> to your provider URL.</li></ul><h2 id="_3-add-api-key" tabindex="-1">3. Add API key <a class="header-anchor" href="#_3-add-api-key" aria-label="Permalink to &quot;3. Add API key&quot;">​</a></h2><p>Add the API key field for your current provider.</p><p>Companion stores keys locally at:</p><p><code>/.obsidian/plugins/sprout/configuration/api-keys.json</code></p><p>The folder name remains <code>sprout</code> for compatibility, even though the plugin name is LearnKit.</p><h2 id="_4-protect-your-key-in-git" tabindex="-1">4. Protect your key in Git <a class="header-anchor" href="#_4-protect-your-key-in-git" aria-label="Permalink to &quot;4. Protect your key in Git&quot;">​</a></h2><p>If your vault or <code>.obsidian</code> directory is tracked by Git, add only this file to <code>.gitignore</code>:</p><div class="language-gitignore vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gitignore</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.obsidian/plugins/sprout/configuration/api-keys.json</span></span></code></pre></div><h2 id="_5-understand-risks-before-use" tabindex="-1">5. Understand risks before use <a class="header-anchor" href="#_5-understand-risks-before-use" aria-label="Permalink to &quot;5. Understand risks before use&quot;">​</a></h2><p>Companion is a draft companion and can hallucinate or be wrong.</p><p>Before relying on responses or generated cards:</p><ul><li>Verify key facts against your source notes.</li><li>Edit wording and difficulty.</li><li>Remove content that is unsafe, low quality, or off-topic.</li></ul><p>Read the full policy: <a href="./AI-Usage-Policy">AI Usage Policy</a></p><h2 id="setup-checklist" tabindex="-1">Setup checklist <a class="header-anchor" href="#setup-checklist" aria-label="Permalink to &quot;Setup checklist&quot;">​</a></h2><ul><li>Companion enabled</li><li>Provider selected</li><li>OpenRouter model access set (if using OpenRouter)</li><li>Model selected</li><li>API key saved</li><li><code>.gitignore</code> includes <code>configuration/api-keys.json</code> only (if needed)</li><li>AI policy reviewed</li></ul>',25)])])}const h=o(a,[["render",r]]);export{g as __pageData,h as default};
